#include "smart_home/segment_recorder.hpp"
#include <fstream>
#include <iostream>

class Source:public smart_home::MediaSource{public:int i=0;smart_home::VideoMetadata open(std::uint32_t id,const std::string&){return smart_home::VideoMetadata{id,27,10,10,1,1000,{}};}bool read(smart_home::VideoPacket& p){if(i==5)return false;p=smart_home::VideoPacket{1,static_cast<std::uint32_t>(i+1),i*1000,i*1000,(i%2==0)?1U:0U,std::vector<std::uint8_t>(4,static_cast<std::uint8_t>(i))};++i;return true;}void request_stop(){}void close(){}};
class Writer:public smart_home::TsSegmentWriter{public:std::ofstream out;void open(const std::string& p,const smart_home::VideoMetadata&){out.open(p.c_str(),std::ios::binary);}void write(const smart_home::VideoPacket& p){out.write(reinterpret_cast<const char*>(&p.data[0]),p.data.size());}void close(){out.close();}};
int main(){smart_home::MountedStorage storage("segment_recorder_test_storage");smart_home::InMemoryRecordingRepository repo;std::unique_ptr<smart_home::MediaSource> source(new Source());smart_home::SegmentRecorder recorder(std::move(source),[]{return std::unique_ptr<smart_home::TsSegmentWriter>(new Writer());},repo,storage,2000);recorder.mark_discontinuity();recorder.run(1,0,"rtsp://test");std::vector<smart_home::RecordingSegment> segments=repo.query(1,0,0,INT64_MAX);if(segments.size()!=3||!segments[0].discontinuity)return 1;for(std::size_t i=0;i<segments.size();++i){if(segments[i].size_bytes==0||segments[i].checksum.size()!=32)return 1;storage.remove_file(segments[i].path);}std::cout<<"TS segment recorder rotation test passed"<<std::endl;return 0;}
